import { Mail, Linkedin, Github, Phone, Download } from 'lucide-react';
import GlassCard from './GlassCard';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';

const links = [
  { href:'mailto:karemalwy1@gmail.com',             label:'karemalwy1@gmail.com', Icon:Mail    },
  { href:'https://www.linkedin.com/in/karem-basem', label:'LinkedIn',             Icon:Linkedin },
  { href:'https://github.com/Kareem-Basem',          label:'GitHub',               Icon:Github  },
  { href:'tel:+201062294558',                        label:'+20 106 229 4558',     Icon:Phone   },
  { href:'/assets/kareem-cv.pdf', label:'Download CV', Icon:Download, download:'Kareem_Basem_CV.pdf' },
];

export default function Contact() {
  const { dark, lang } = useApp();
  const tr  = t[lang];
  const bg  = dark ? '#0a0a10' : '#1a1a2e';
  const ink = dark ? '#f0f0f8' : '#ffffff';
  const sub = dark ? 'rgba(255,255,255,0.42)' : 'rgba(255,255,255,0.52)';

  return (
    <>
      <section id="contact" style={{ background:bg }} className="py-28 px-[5%] relative overflow-hidden transition-colors duration-300">
        {/* Subtle ambient glow */}
        <div className="absolute pointer-events-none"
          style={{ width:600, height:400, borderRadius:'50%', background:'radial-gradient(circle,rgba(240,165,0,0.07),transparent 70%)', top:'50%', left:'50%', transform:'translate(-50%,-50%)' }}/>
        <div className="blob-hero w-[400px] h-[400px] opacity-[.04] top-[-80px] right-[-80px]"
          style={{ background:'#f0a500', position:'absolute', pointerEvents:'none' }}/>

        <div className="relative z-10 max-w-2xl">
          <div className="reveal">
            <span className="inline-block text-xs font-semibold tracking-[.14em] uppercase mb-3 px-3 py-1 rounded-full"
              style={{ background:'rgba(240,165,0,0.12)', border:'1px solid rgba(240,165,0,0.28)', color:'#f0a500' }}>
              {tr.conTag}
            </span>
          </div>

          <h2 className="reveal font-serif-display tracking-tight leading-[.92] mb-5 d1"
            style={{ fontSize:'clamp(3rem,7vw,6rem)', color:ink }}
            dangerouslySetInnerHTML={{ __html: tr.conTitle.replace('<em>',`<em style="font-style:italic;color:#f0a500;font-family:'DM Serif Display',serif;">`).replace('</em>','</em>') }}/>

          <p className="reveal d2 text-[.96rem] leading-[1.8] mb-8 max-w-[460px]" style={{ color:sub }}>{tr.conSub}</p>

          <div className="reveal d3 flex flex-wrap gap-2.5">
            {links.map((l) => { const { href, label, Icon } = l; return (
              <a key={label} href={href}
                target={href.startsWith('http') ? '_blank' : undefined} rel="noreferrer"
                className="flex items-center gap-2 px-4 py-2.5 rounded-full text-sm font-medium transition-all hover:-translate-y-0.5"
                download={l.download || undefined}
                style={{
                  background: l.download ? 'rgba(240,165,0,0.10)' : 'rgba(255,255,255,0.07)',
                  border: l.download ? '1.5px solid rgba(240,165,0,0.35)' : '1.5px solid rgba(255,255,255,0.15)',
                  color: l.download ? '#f0a500' : 'rgba(255,255,255,0.62)',
                  backdropFilter:'blur(12px)',
                }}
                onMouseEnter={e => { e.currentTarget.style.borderColor='#f0a500'; e.currentTarget.style.color='#f0a500'; e.currentTarget.style.background='rgba(240,165,0,0.10)'; }}
                onMouseLeave={e => {
                  e.currentTarget.style.borderColor = l.download ? 'rgba(240,165,0,0.35)' : 'rgba(255,255,255,0.15)';
                  e.currentTarget.style.color = l.download ? '#f0a500' : 'rgba(255,255,255,0.62)';
                  e.currentTarget.style.background = l.download ? 'rgba(240,165,0,0.10)' : 'rgba(255,255,255,0.07)';
                }}>
                <Icon size={14}/>{label}
              </a>
            );})}
          </div>
        </div>
      </section>

      <footer style={{ background:dark?'#06060a':'#0d0d1a' }}
        className="px-[5%] py-5 flex flex-col md:flex-row justify-between items-center gap-2 transition-colors duration-300">
        <span className="text-[.72rem]" style={{ color:'rgba(255,255,255,0.22)' }}>© 2025 Kareem Basem Fathi</span>
        <span className="text-[.72rem]" style={{ color:'rgba(255,255,255,0.22)' }}>MIS · Sadat Academy · Asyut, Egypt</span>
      </footer>
    </>
  );
}
